using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Newtonsoft.Json;

namespace MyApi {
    [Route("api/[controller]")]
    [ApiController]
    public class UsersController : ControllerBase {
        private readonly string _connectionString = "Server=my_server;Database=my_database;User ID=my_user;Password=my_password";

        [HttpGet("{email}")]
        public async Task<IActionResult> GetUsersByEmail([FromQuery] string email) {
            var users = new List<User>();

            using (var connection = new SqlConnection(_connectionString)) {
                await connection.OpenAsync();

                using (var command = new SqlCommand("SELECT * FROM Users WHERE Email = @email", connection)) {
                    command.Parameters.AddWithValue("@email", email);

                    using (var reader = await command.ExecuteReaderAsync()) {
                        while (await reader.ReadAsync()) {
                            users.Add(new User() {
                                Id = Convert.ToInt32(reader["Id"]),
                                Email = reader["Email"].ToString(),
                                Name = reader["Name"].ToString(),
                                Age = Convert.ToInt32(reader["Age"])
                            });
                        }
                    }
                }
            }

            return JsonConvert.SerializeObject(users);
        }
    }

    public class User {
        public int Id { get; set; }
        public string Email { get; set; }
        public string Name { get; set; }
        public int Age { get; set; }
    }
}